import React from 'react';
import {
  Bot, MessageSquare, BookOpen, GitBranch, BarChart2,
  ChevronRight, LayoutDashboard, Calendar, ShoppingCart,
  ShoppingBag, Megaphone, Users, Calculator, TrendingUp,
  Ticket, BadgeCheck, Kanban, Shield, Building2, Wallet,
  CheckCircle2, AlertCircle, Rocket, MessageCircle,
  LayoutGrid, Mail, Database, ExternalLink, Clock
} from 'lucide-react';

// VARIANT A: Clarity of information hierarchy
// Tradeoff: three explicit visual tiers throughout.
// Tier 1 = section banner (full-width label with left accent bar).
// Tier 2 = card title (14px bold with icon).
// Tier 3 = metric row (10px label / 13px value).
// Module grid uses domain separators (IA & WhatsApp / ERP & Finanzas / Operaciones).
// Onboarding uses a numbered timeline, not icon-only pills.
// KPI cards have a colored left border strip for at-a-glance status.

const NAVY = '#07102A';
const CARD = '#0D1B2E';
const CARD2 = '#0A1624';
const ACCENT = '#10B981';
const STEEL = '#7A8FA0';
const SILVER = '#B8C5D0';
const BORDER = 'rgba(180,200,220,0.12)';

const funnel = [
  { label:'Mensajes recibidos',          val:'8.412', pct:100, color:'#3B82F6' },
  { label:'Coincidencia de intenciones', val:'7.318', pct:87,  color:'#8B5CF6' },
  { label:'Resueltos por KB',            val:'6.561', pct:78,  color:'#10B981' },
  { label:'Fallback RAG/IA',             val:'757',   pct:9,   color:'#F59E0B' },
  { label:'Escalados a humanos',         val:'589',   pct:7,   color:'#EF4444' },
];

const msgDays = [
  { d:'Lu', v:60 },{ d:'Ma', v:72 },{ d:'Mi', v:55 },
  { d:'Ju', v:88 },{ d:'Vi', v:95 },{ d:'Sa', v:40 },{ d:'Do', v:30 },
];

const steps = [
  { n:1, done:true,  label:'Cuenta creada',        desc:'Tu cuenta está activa' },
  { n:2, done:false, label:'Base de conocimiento', desc:'Agregá info de tu negocio' },
  { n:3, done:false, label:'Conectar WhatsApp',    desc:'Configurá Evolution API' },
  { n:4, done:false, label:'Activar chatbot',      desc:'Activá el bot en configuración' },
  { n:5, done:false, label:'Primera conversación', desc:'Enviá un mensaje de prueba' },
];

const modules = [
  {
    domain: 'IA & WhatsApp',
    items: [
      { icon: Bot,        ic:'#10B981', ib:'rgba(16,185,129,0.12)', title:'Agente IA',        rows:[{l:'Estado',v:'Inactivo',w:true},{l:'Conversaciones',v:'0'},{l:'Knowledge',v:'0 KB',w:true}] },
      { icon: GitBranch,  ic:'#8B5CF6', ib:'rgba(139,92,246,0.12)', title:'Flows',             rows:[{l:'Flows activos',v:'4'},{l:'Ejecuciones hoy',v:'382'},{l:'Tasa éxito',v:'94%',a:true}] },
      { icon: Megaphone,  ic:'#EC4899', ib:'rgba(236,72,153,0.12)', title:'Difusión Masiva',   rows:[{l:'Campaña activa',v:'1'},{l:'Destinatarios',v:'1.240'},{l:'Apertura',v:'68%',a:true}] },
      { icon: MessageCircle, ic:'#3B82F6', ib:'rgba(59,130,246,0.12)', title:'Chat & Chatbot', rows:[{l:'Handoffs activos',v:'0'},{l:'SLA cumplido',v:'—'},{l:'Respuesta promedio',v:'—'}] },
    ]
  },
  {
    domain: 'ERP & Finanzas',
    items: [
      { icon: BarChart2,  ic:'#3B82F6', ib:'rgba(59,130,246,0.12)',   title:'CRM & Ventas',  rows:[{l:'Pipeline',v:'$1.743K'},{l:'Deals activos',v:'7'},{l:'Ganado mes',v:'$55K',a:true}] },
      { icon: Building2,  ic:'#F97316', ib:'rgba(249,115,22,0.12)',   title:'ERP',            rows:[{l:'Por cobrar',v:'$338K'},{l:'Cobrado mes',v:'$150K',a:true},{l:'Alertas stock',v:'2',w:true}] },
      { icon: Calculator, ic:'#A855F7', ib:'rgba(168,85,247,0.12)',   title:'Contabilidad',   rows:[{l:'Ingresos jun.',v:'$1.285K'},{l:'Gastos jun.',v:'$719K'},{l:'Neto',v:'$565K',a:true}] },
      { icon: TrendingUp, ic:'#22C55E', ib:'rgba(34,197,94,0.12)',    title:'Finanzas',       rows:[{l:'Saldo ARS',v:'$8.16M'},{l:'Saldo USD',v:'U$D 12.840',a:true},{l:'Por conciliar',v:'2',w:true}] },
    ]
  },
  {
    domain: 'Operaciones',
    items: [
      { icon: Ticket,    ic:'#EAB308', ib:'rgba(234,179,8,0.12)',    title:'Soporte',         rows:[{l:'Tickets abiertos',v:'5'},{l:'SLA incumplido',v:'1',w:true},{l:'Cumpl. SLA',v:'86%',a:true}] },
      { icon: BadgeCheck,ic:'#EC4899', ib:'rgba(236,72,153,0.12)',   title:'RRHH',            rows:[{l:'Empleados activos',v:'7'},{l:'Masa salarial',v:'$2.75M'},{l:'Ausencias',v:'2',w:true}] },
      { icon: Calendar,  ic:'#A855F7', ib:'rgba(168,85,247,0.12)',   title:'Agenda de Turnos',rows:[{l:'Turnos hoy',v:'12'},{l:'Pendientes',v:'4'},{l:'Confirmados',v:'8',a:true}] },
      { icon: ShoppingCart, ic:'#F97316', ib:'rgba(249,115,22,0.12)',title:'Pedidos',          rows:[{l:'Pedidos activos',v:'18'},{l:'Entregados hoy',v:'5',a:true},{l:'Cancelados',v:'1',w:true}] },
    ]
  }
];

function SectionBanner({ label }: { label: string }) {
  return (
    <div className="flex items-center gap-3 mb-4">
      <div className="w-1 h-5 rounded-full flex-shrink-0" style={{ backgroundColor: ACCENT }}></div>
      <span className="text-xs font-black uppercase tracking-[0.14em]" style={{ color: STEEL }}>{label}</span>
    </div>
  );
}

function ModuleCard({ icon: Icon, ic, ib, title, rows }: any) {
  return (
    <div className="rounded-2xl p-4 flex flex-col gap-3 cursor-pointer group" style={{ backgroundColor: CARD, border: `1px solid ${BORDER}` }}>
      <div className="flex items-center gap-2.5">
        <div className="w-7 h-7 rounded-lg flex items-center justify-center flex-shrink-0" style={{ backgroundColor: ib }}>
          <Icon size={14} style={{ color: ic }} />
        </div>
        <span className="text-xs font-bold leading-tight group-hover:text-white transition-colors" style={{ color: SILVER }}>{title}</span>
        <ChevronRight size={12} className="ml-auto opacity-20 group-hover:opacity-60 transition-opacity" style={{ color: SILVER }} />
      </div>
      <div className="space-y-1.5">
        {rows.map((r: any) => (
          <div key={r.l} className="flex items-center justify-between">
            <span className="text-[10px]" style={{ color: STEEL }}>{r.l}</span>
            <span className="text-xs font-bold" style={{ color: r.a ? ACCENT : r.w ? '#F87171' : SILVER }}>{r.v}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export function OverviewA() {
  const completed = steps.filter(s => s.done).length;
  const pct = Math.round((completed / steps.length) * 100);

  return (
    <div className="h-screen overflow-auto p-6 space-y-8" style={{ backgroundColor: NAVY, fontFamily: 'system-ui, sans-serif' }}>

      {/* ── ONBOARDING: numbered timeline instead of icon pills ── */}
      <div>
        <SectionBanner label="Configuración inicial" />
        <div className="rounded-2xl p-5" style={{ backgroundColor: CARD, border: `1px solid rgba(16,185,129,0.2)` }}>
          <div className="flex items-center justify-between mb-5">
            <div>
              <p className="text-sm font-bold text-white flex items-center gap-2">
                <Rocket size={14} style={{ color: ACCENT }} />
                Completá tu setup
              </p>
              <p className="text-xs mt-0.5" style={{ color: STEEL }}>{completed} de {steps.length} pasos listos</p>
            </div>
            <div className="text-right">
              <p className="text-2xl font-black" style={{ color: ACCENT }}>{pct}%</p>
              <div className="w-28 h-1.5 rounded-full mt-1" style={{ backgroundColor: 'rgba(180,200,220,0.12)' }}>
                <div className="h-1.5 rounded-full transition-all" style={{ backgroundColor: ACCENT, width: `${pct}%` }} />
              </div>
            </div>
          </div>

          {/* Numbered timeline — tier 2 label is clearly larger than tier 3 desc */}
          <div className="relative flex gap-0">
            {steps.map((step, i) => (
              <div key={i} className="flex-1 flex flex-col items-center gap-2 relative">
                {i < steps.length - 1 && (
                  <div className="absolute top-3.5 left-1/2 w-full h-px" style={{ backgroundColor: step.done ? 'rgba(16,185,129,0.35)' : 'rgba(180,200,220,0.1)' }}></div>
                )}
                <div className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-black z-10 flex-shrink-0" style={{
                  backgroundColor: step.done ? ACCENT : CARD2,
                  color: step.done ? NAVY : STEEL,
                  border: step.done ? 'none' : `1px solid ${BORDER}`,
                }}>
                  {step.done ? <CheckCircle2 size={14} /> : step.n}
                </div>
                {/* Tier 2 label */}
                <p className="text-[10px] font-bold text-center leading-tight px-1" style={{ color: step.done ? ACCENT : SILVER }}>{step.label}</p>
                {/* Tier 3 desc */}
                <p className="text-[9px] text-center leading-tight px-1 hidden lg:block" style={{ color: STEEL }}>{step.desc}</p>
              </div>
            ))}
          </div>

          <a href="#" className="inline-flex items-center gap-2 mt-5 text-xs font-bold px-4 py-2 rounded-xl transition-all" style={{ backgroundColor: ACCENT, color: NAVY }}>
            <BookOpen size={12} /> Siguiente: Base de conocimiento →
          </a>
        </div>
      </div>

      {/* ── KPI CHATBOT IA: colored left-border strips convey status at a glance ── */}
      <div>
        <SectionBanner label="Agente IA & WhatsApp" />
        <div className="grid grid-cols-4 gap-4 mb-4">
          {[
            { label:'Estado del bot',        value:'Inactivo', sub:'Sin WhatsApp',        strip:'#EF4444', subColor:'#F87171' },
            { label:'Conversaciones',        value:'0',        sub:'total acumulado',     strip:'#3B82F6', subColor:STEEL },
            { label:'Base de conocimiento',  value:'0',        sub:'KB vacía — agregá contenido', strip:'#F59E0B', subColor:'#FCD34D' },
            { label:'Handoffs activos',      value:'0',        sub:'bot respondiendo todo', strip:'#10B981', subColor:STEEL },
          ].map((kpi, i) => (
            <div key={i} className="rounded-2xl overflow-hidden" style={{ backgroundColor: CARD, border: `1px solid ${BORDER}` }}>
              {/* Tier 1: status strip */}
              <div className="h-1" style={{ backgroundColor: kpi.strip }}></div>
              <div className="p-5">
                {/* Tier 2: label */}
                <p className="text-[10px] font-bold uppercase tracking-wider mb-3" style={{ color: STEEL }}>{kpi.label}</p>
                {/* Tier 1: value */}
                <p className="text-2xl font-extrabold mb-1.5" style={{ color: i === 0 ? '#F87171' : 'white' }}>{kpi.value}</p>
                {/* Tier 3: sublabel */}
                <p className="text-[10px] flex items-center gap-1" style={{ color: kpi.subColor }}>
                  {i === 0 && <AlertCircle size={10} />}
                  {i === 2 && <AlertCircle size={10} />}
                  {kpi.sub}
                </p>
              </div>
            </div>
          ))}
        </div>

        <div className="grid grid-cols-2 gap-4">
          {/* Chart */}
          <div className="rounded-2xl p-5" style={{ backgroundColor: CARD, border: `1px solid ${BORDER}` }}>
            <div className="flex items-center justify-between mb-4">
              <SectionBanner label="Volumen semanal" />
