    warning: { icon: AlertTriangle, label: 'Atención',  color: '#FDE047', bg: 'rgba(253,224,71,0.12)' },
    error:   { icon: XCircle,       label: 'Inactivo',  color: '#F87171', bg: 'rgba(248,113,113,0.12)' },
    info:    { icon: CircleDot,     label: 'Escaneando',color: '#93C5FD', bg: 'rgba(147,197,253,0.12)' },
  }[status];
  const Icon = cfg.icon;
  return (
    <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold" style={{ backgroundColor: cfg.bg, color: cfg.color }}>
      <Icon size={11} aria-hidden="true" />
