    41→      if (!loader) {
    42→        setError(`No component found at ${componentPath}.tsx`);
    43→        return;
    44→      }
    45→
    46→      try {
    47→        const mod = await loader();
    48→        if (cancelled) {
    49→          return;
    50→        }
    51→        const name = componentPath.split("/").pop()!;
    52→        const comp = _resolveComponent(mod, name);
    53→        if (!comp) {
