import React, { useState } from 'react';
import { CheckCircle2, ChevronDown, ChevronUp } from 'lucide-react';

// LANDING VARIANT A — Clarity of information hierarchy
// Every section has an explicit 4-level typographic stack:
//   L1: OVERLINE LABEL (10px bold uppercase, primary color)
//   L2: Section H2 (36–48px extrabold)
//   L3: Subtext / description (16–18px, muted)
//   L4: Supporting detail / fine print (12px)
//
// Tradeoff: more visual structure, less whitespace breathing room.
// Numbered problem cards (01–04) act as a scan anchor.
// Plans: name → price → billing note → feature list (never mixed levels).
// ROI calculator: labels above every input, never inline.

const NAVY = '#031E43';
const STEEL = '#3B506D';
const ACCENT = '#06B6D4';
const GREEN = '#10B981';
const BG = '#FDFDFB';
const MUTED = '#F0F2F5';
const BORDER = '#DDDFE2';
const WHITE = '#FFFFFF';

const plans = [
  { name:'Free',       price:'$0',       billing:'Gratis para siempre',          cta:'Empezar gratis',  highlight:false, features:['1 usuario','Chatbot básico','100 msgs/mes','Soporte comunidad'] },
  { name:'Starter',   price:'$180K',    billing:'/mes · ARS',                    cta:'Elegir Starter',  highlight:false, features:['3 usuarios','CRM + Pipeline','500 msgs/mes','Soporte email'] },
  { name:'Pro',        price:'$350K',    billing:'/mes · ARS',                    cta:'Elegir Pro',       highlight:true,  features:['10 usuarios','ERP + Contabilidad','2.000 msgs/mes','Soporte prioritario'] },
  { name:'Business',  price:'$600K',    billing:'/mes · ARS',                    cta:'Elegir Business',  highlight:false, features:['Ilimitado','Suite completa','10K msgs/mes','SLA garantizado'] },
  { name:'Enterprise',price:'A consultar', billing:'Precio personalizado',        cta:'Contactar',        highlight:false, features:['Equipo ilimitado','White label','Custom SLA','Implementación dedicada'] },
];

const faqs = [
  { q:'¿Necesito conocimientos técnicos?', a:'No. Clientum está diseñado para que cualquier dueño de PyME lo pueda usar sin tocar código. Nosotros nos encargamos de la configuración inicial.' },
  { q:'¿Cuánto tarda la implementación?', a:'El onboarding básico toma 1-2 días hábiles. La implementación completa con ERP y CRM puede tardar 1-2 semanas.' },
  { q:'¿Qué pasa si supero el límite de mensajes?', a:'El chatbot pausa las respuestas automáticas y te notifica. Podés actualizar tu plan en cualquier momento desde el dashboard.' },
  { q:'¿Puedo cancelar cuando quiera?', a:'Sí. Todos los planes son mensuales y podés cancelar en cualquier momento sin penalidad.' },
];

export function LandingA() {
  const [openFaq, setOpenFaq] = useState<number | null>(null);
  const [isAnnual, setIsAnnual] = useState(false);

  // ROI calculator state
  const [emp, setEmp] = useState(5);
  const [hrs, setHrs] = useState(3);
  const perdida = emp * hrs * 22 * 15000 * 0.4;
  const ventas = 30 * 50000 * 0.3;
  const total = perdida + ventas;
  const fmt = (n: number) => `$${Math.round(n / 1000)}K`;

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', backgroundColor: BG, color: NAVY, overflowX: 'hidden' }}>

      {/* ── TICKER ── */}
      <div style={{ backgroundColor: '#DDDFE2', borderBottom: `1px solid ${BORDER}`, padding: '6px 0', overflow: 'hidden' }}>
        <div style={{ display: 'flex', gap: 48, fontSize: 11, fontWeight: 700, color: STEEL, whiteSpace: 'nowrap', paddingLeft: 24 }}>
          <span>🟢 +500 PyMEs confían en Clientum</span>
          <span>⚡ 3 hs ahorradas por día en promedio</span>
          <span>🤖 80% consultas resueltas automáticamente</span>
          <span>🎁 Diagnóstico 100% gratis y sin compromiso</span>
          <span>⭐ 98% de satisfacción de clientes</span>
        </div>
      </div>

