import React, { useState } from 'react';
import { ArrowRight, Play, CheckCircle2, ChevronDown, ChevronUp, ExternalLink } from 'lucide-react';

// LANDING VARIANT B — Ease of interaction and affordance visibility
// Every interactive element announces what it does before the user clicks.
// Tradeoff: more UI chrome, intentionally "louder" — affordances compete for attention.
//
// Key patterns:
// - Nav links show an underline animation on hover with explicit label
// - Primary CTA has an arrow that slides right on hover
// - Video section has a Play button overlay with pulsing ring
// - Problem cards are full-card clickable links with border animation
// - Solution cards have "Ver demo →" link that grows in on hover
// - ROI result card has a pulsing highlight on the total
// - Plan cards: hover lifts card + shows "Elegir este plan →"
// - FAQ: chevron icon changes color when open, explicit "Leer respuesta" label
// - Footer: WhatsApp button has the WhatsApp icon inline

const NAVY = '#031E43';
const STEEL = '#3B506D';
const GREEN = '#10B981';
const ACCENT = '#06B6D4';
