function HovCard({ children, onClick }: { children: React.ReactNode, onClick?: () => void }) {
  const [hov, setHov] = useState(false);
  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: WHITE,
        borderRadius: 20,
        padding: 28,
        border: `2px solid ${hov ? NAVY : BORDER}`,
        cursor: 'pointer',
        transition: 'all 0.18s',
        transform: hov ? 'translateY(-3px)' : 'none',
        boxShadow: hov ? '0 8px 32px rgba(3,30,67,0.12)' : '0 1px 4px rgba(0,0,0,0.04)',
      }}
    >
      {children}
    </div>
  );
}

function PlanCard({ plan }: { plan: typeof plans[0] }) {
