// Status badge: always icon + text + color
function StatusPill({ type }: { type: 'active' | 'warning' | 'popular' }) {
  const cfg = {
    active:  { icon: CheckCircle2, label: 'Activo', bg: 'rgba(5,150,105,0.1)', color: GREEN },
    warning: { icon: AlertCircle,  label: 'Atención', bg: 'rgba(185,28,28,0.1)', color: WARN_RED },
    popular: { icon: CheckCircle2, label: 'Más popular', bg: 'rgba(2,132,199,0.1)', color: ACCENT },
  }[type];
  const Icon = cfg.icon;
  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, padding: '4px 10px', borderRadius: 99, background: cfg.bg, color: cfg.color, fontSize: 12, fontWeight: 700 }}>
      <Icon size={12} aria-hidden="true" />
      {cfg.label}
    </span>
  );
}

