import React, { useState } from 'react';
import {
  Bot, BookOpen, GitBranch, BarChart2, ChevronRight,
  Calendar, ShoppingCart, Megaphone, Calculator, TrendingUp,
  Ticket, BadgeCheck, Building2, CheckCircle2, AlertCircle,
  Rocket, MessageCircle, LayoutGrid, Mail, Database,
  Clock, CircleDot, XCircle, AlertTriangle, Activity,
  Zap, Users, ArrowRight
} from 'lucide-react';

// VARIANT C1: SPLIT PANEL
// Left column (35%) = persistent status panel: onboarding tracker + channels
// Right column (65%) = data area: KPI row → chart+funnel → module grid
// Hierarchy: spatial separation replaces section headers.
// Status lives on the left; metrics and actions live on the right.
// Result: everything visible in one viewport; left tracks health, right drives action.

const NAVY = '#07102A';
const CARD = '#0D1B2E';
const CARD2 = '#0A1624';
const SIDE = '#0A1522';
const ACCENT = '#10B981';
const ACCENT_DARK = '#059669';
const SILVER = '#C0CDD8';
const STEEL = '#8A9FB0';
const BORDER = 'rgba(180,200,220,0.13)';
const WHITE = '#FFFFFF';

const steps = [
  { done:true,  icon:CheckCircle2,  label:'Cuenta creada',        desc:'Activa' },
  { done:false, icon:BookOpen,      label:'Base de conocimiento', desc:'Pendiente' },
  { done:false, icon:MessageCircle, label:'Conectar WhatsApp',    desc:'Pendiente' },
  { done:false, icon:Bot,           label:'Activar chatbot',      desc:'Pendiente' },
  { done:false, icon:CircleDot,     label:'Primera conversación', desc:'Pendiente' },
];

const modules = [
  { icon:BarChart2,    ic:'#60A5FA', ib:'rgba(96,165,250,0.12)',  title:'CRM & Ventas',    rows:[{l:'Pipeline',v:'$1.743K'},{l:'Deals activos',v:'7'},{l:'Ganado',v:'$55K',a:true}] },
  { icon:Building2,    ic:'#FB923C', ib:'rgba(251,146,60,0.12)',  title:'ERP',              rows:[{l:'Por cobrar',v:'$338K'},{l:'Cobrado',v:'$150K',a:true},{l:'Alertas stock',v:'2',w:true}] },
  { icon:Calculator,   ic:'#C084FC', ib:'rgba(192,132,252,0.12)', title:'Contabilidad',     rows:[{l:'Ingresos',v:'$1.285K'},{l:'Gastos',v:'$719K'},{l:'Neto',v:'$565K',a:true}] },
  { icon:TrendingUp,   ic:'#4ADE80', ib:'rgba(74,222,128,0.12)',  title:'Finanzas',         rows:[{l:'Saldo ARS',v:'$8.16M'},{l:'Saldo USD',v:'U$12.840',a:true},{l:'Conciliar',v:'2',w:true}] },
  { icon:Ticket,       ic:'#FDE047', ib:'rgba(253,224,71,0.12)',  title:'Soporte',          rows:[{l:'Abiertos',v:'5'},{l:'SLA incumplido',v:'1',w:true},{l:'SLA %',v:'86%',a:true}] },
  { icon:BadgeCheck,   ic:'#F472B6', ib:'rgba(244,114,182,0.12)', title:'RRHH',             rows:[{l:'Empleados',v:'7'},{l:'Masa salarial',v:'$2.75M'},{l:'Ausencias',v:'2',w:true}] },
  { icon:Calendar,     ic:'#C084FC', ib:'rgba(192,132,252,0.12)', title:'Turnos',           rows:[{l:'Hoy',v:'12'},{l:'Pendientes',v:'4'},{l:'Confirmados',v:'8',a:true}] },
  { icon:ShoppingCart, ic:'#FB923C', ib:'rgba(251,146,60,0.12)',  title:'Pedidos',          rows:[{l:'Activos',v:'18'},{l:'Entregados',v:'5',a:true},{l:'Cancelados',v:'1',w:true}] },
];

const channels = [
  { icon:MessageCircle, ic:'#F87171', title:'WhatsApp',  status:'Inactivo',  statusColor:'#F87171', statusBg:'rgba(248,113,113,0.12)' },
  { icon:LayoutGrid,    ic:'#60A5FA', title:'Catálogo',  status:'Sin publicar',statusColor:'#FDE047',statusBg:'rgba(253,224,71,0.12)' },
  { icon:Mail,          ic:'#60A5FA', title:'Gmail',     status:'Escaneando', statusColor:'#93C5FD', statusBg:'rgba(147,197,253,0.12)' },
  { icon:Database,      ic:'#FDE047', title:'PostgreSQL',status:'OK',         statusColor:'#4ADE80', statusBg:'rgba(74,222,128,0.12)' },
];

const chartData = [
  { d:'Lu', v:60 },{ d:'Ma', v:72 },{ d:'Mi', v:55 },
  { d:'Ju', v:88 },{ d:'Vi', v:95 },{ d:'Sa', v:40 },{ d:'Do', v:30 },
];

export function OverviewC1() {
  const completed = steps.filter(s => s.done).length;
  const pct = Math.round((completed / steps.length) * 100);
  const nextStep = steps.find(s => !s.done);
  const [activeKpi] = useState(0);

  return (
    <div className="flex h-screen overflow-hidden" style={{ backgroundColor: NAVY, fontFamily: 'system-ui, -apple-system, sans-serif' }}>

      {/* ═══ LEFT SIDEBAR — status panel ═══ */}
      <aside className="flex-shrink-0 w-[300px] overflow-y-auto flex flex-col gap-5 p-5 border-r" style={{ backgroundColor: SIDE, borderColor: BORDER }}>

        {/* App header */}
        <div className="flex items-center gap-2 pb-3 border-b" style={{ borderColor: BORDER }}>
          <div className="w-7 h-7 rounded-lg flex items-center justify-center" style={{ backgroundColor: ACCENT }}>
            <Zap size={14} color={NAVY} />
          </div>
          <span className="font-bold text-sm" style={{ color: WHITE }}>Clientum</span>
          <span className="ml-auto text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ backgroundColor: 'rgba(16,185,129,0.12)', color: ACCENT }}>Overview</span>
        </div>

        {/* Onboarding — vertical stepper */}
        <div className="rounded-xl p-4" style={{ backgroundColor: CARD, border: `1px solid rgba(16,185,129,0.18)` }}>
          <div className="flex items-center justify-between mb-3">
            <p className="text-xs font-bold" style={{ color: WHITE }}>Configuración inicial</p>
            <p className="text-base font-black" style={{ color: ACCENT }}>{pct}%</p>
          </div>
          <div className="h-1.5 rounded-full mb-4" style={{ backgroundColor: 'rgba(180,200,220,0.08)' }}>
            <div className="h-full rounded-full transition-all" style={{ backgroundColor: ACCENT, width: `${pct}%` }} />
          </div>

          {/* Vertical steps */}
          <div className="space-y-1">
            {steps.map((step, i) => {
              const Icon = step.icon;
              const isNext = !step.done && steps.slice(0, i).every(s => s.done);
              return (
                <div key={i} className="flex items-center gap-3 py-2 px-2 rounded-lg" style={{
                  backgroundColor: isNext ? 'rgba(16,185,129,0.08)' : 'transparent',
                }}>
                  <div className="w-6 h-6 rounded-full flex items-center justify-center flex-shrink-0" style={{
