  Bot, BookOpen, BarChart2, ChevronRight,
  Calendar, ShoppingCart, Calculator, TrendingUp,
  Ticket, BadgeCheck, Building2, CheckCircle2,
  Rocket, MessageCircle, LayoutGrid, Mail, Database,
  CircleDot, AlertTriangle, XCircle, Activity,
  Zap, ArrowRight, TrendingDown
} from 'lucide-react';

// VARIANT C3: BENTO GRID
// No section headers — content is grouped into asymmetric tiles of varying sizes.
// Visual weight varies by tile size, not by position in a linear scroll.
// Grid rows:
//   Row 1 (3-col): Big onboarding tile (2/3 wide) + bot status tower (1/3 narrow, tall)
//   Row 2 (3-col): Chart (1/3) + Funnel (1/3) + Channels stacked (1/3)
//   Row 3 (4-col): Modules — equal weight, no sub-grouping
// KPI values are embedded inside their relevant tiles, not in a separate row.
// Result: the page reads as a spatial map, not a top-to-bottom list.

const NAVY = '#07102A';
const CARD = '#0D1B2E';
const CARD2 = '#0A1624';
const CARD3 = '#0F1F35';
const ACCENT = '#10B981';
const ACCENT_DARK = '#059669';
const SILVER = '#C0CDD8';
const STEEL = '#8A9FB0';
const BORDER = 'rgba(180,200,220,0.13)';
const WHITE = '#FFFFFF';

const steps = [
  { done:true,  icon:CheckCircle2,  label:'Cuenta creada',        shortLabel:'Cuenta' },
  { done:false, icon:BookOpen,      label:'Base de conocimiento', shortLabel:'KB' },
  { done:false, icon:MessageCircle, label:'Conectar WhatsApp',    shortLabel:'WhatsApp' },
  { done:false, icon:Bot,           label:'Activar chatbot',      shortLabel:'Chatbot' },
  { done:false, icon:CircleDot,     label:'Primera conversación', shortLabel:'Primera conv.' },
];

const chartData = [
  { d:'Lu', v:60 },{ d:'Ma', v:72 },{ d:'Mi', v:55 },
  { d:'Ju', v:88 },{ d:'Vi', v:95 },{ d:'Sa', v:40 },{ d:'Do', v:30 },
];

const modules = [
  { icon:BarChart2,    ic:'#60A5FA', ib:'rgba(96,165,250,0.12)',  title:'CRM & Ventas',  kv:'$1.743K', ks:'Pipeline', rows:[{l:'Deals activos',v:'7'},{l:'Ganado',v:'$55K',a:true}] },
  { icon:Building2,    ic:'#FB923C', ib:'rgba(251,146,60,0.12)',  title:'ERP',            kv:'$338K',   ks:'Por cobrar',rows:[{l:'Cobrado',v:'$150K',a:true},{l:'Alertas',v:'2',w:true}] },
  { icon:Calculator,   ic:'#C084FC', ib:'rgba(192,132,252,0.12)', title:'Contabilidad',   kv:'$565K',   ks:'Resultado neto',rows:[{l:'Ingresos',v:'$1.285K'},{l:'Gastos',v:'$719K'}] },
  { icon:TrendingUp,   ic:'#4ADE80', ib:'rgba(74,222,128,0.12)',  title:'Finanzas',       kv:'$8.16M',  ks:'Saldo ARS', rows:[{l:'USD',v:'U$12.840',a:true},{l:'Conciliar',v:'2',w:true}] },
  { icon:Ticket,       ic:'#FDE047', ib:'rgba(253,224,71,0.12)',  title:'Soporte',        kv:'5',       ks:'Tickets', rows:[{l:'SLA roto',v:'1',w:true},{l:'SLA %',v:'86%',a:true}] },
  { icon:BadgeCheck,   ic:'#F472B6', ib:'rgba(244,114,182,0.12)', title:'RRHH',           kv:'7',       ks:'Empleados', rows:[{l:'Masa sal.',v:'$2.75M'},{l:'Ausencias',v:'2',w:true}] },
  { icon:Calendar,     ic:'#C084FC', ib:'rgba(192,132,252,0.12)', title:'Turnos',         kv:'12',      ks:'Hoy', rows:[{l:'Pendientes',v:'4'},{l:'Confirmados',v:'8',a:true}] },
  { icon:ShoppingCart, ic:'#FB923C', ib:'rgba(251,146,60,0.12)',  title:'Pedidos',        kv:'18',      ks:'Activos', rows:[{l:'Entregados',v:'5',a:true},{l:'Cancelados',v:'1',w:true}] },
];

export function OverviewC3() {
  const completed = steps.filter(s => s.done).length;
  const pct = Math.round((completed / steps.length) * 100);
  const nextStep = steps.find(s => !s.done);

  return (
    <div className="h-screen overflow-y-auto p-4 space-y-3" style={{ backgroundColor: NAVY, fontFamily: 'system-ui, -apple-system, sans-serif' }}>

      {/* ══ ROW 1: Onboarding (2/3) + Bot KPI tower (1/3) ══ */}
      <div className="grid grid-cols-3 gap-3" style={{ minHeight: 200 }}>

        {/* Tile A — Onboarding: wide, medium tall */}
        <div className="col-span-2 rounded-2xl p-5 flex flex-col" style={{ backgroundColor: CARD, border: `1px solid rgba(16,185,129,0.18)` }}>
          <div className="flex items-start justify-between mb-4">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <Zap size={14} style={{ color: ACCENT }} />
                <p className="text-sm font-bold" style={{ color: WHITE }}>Configuración inicial</p>
              </div>
              <p className="text-xs" style={{ color: STEEL }}>Seguí estos pasos para activar tu agente IA</p>
            </div>
            <div className="text-right flex-shrink-0">
              <p className="text-2xl font-black leading-none" style={{ color: ACCENT }}>{pct}%</p>
              <p className="text-[10px] mt-1" style={{ color: STEEL }}>{completed} de {steps.length}</p>
            </div>
          </div>

          {/* Progress bar */}
          <div className="h-1.5 rounded-full mb-5" style={{ backgroundColor: 'rgba(180,200,220,0.08)' }}>
            <div className="h-full rounded-full transition-all" style={{ backgroundColor: ACCENT, width: `${pct}%` }} />
          </div>

          {/* Steps — horizontal tiles, equal width */}
          <div className="grid grid-cols-5 gap-2 flex-1">
            {steps.map((step, i) => {
              const Icon = step.icon;
              const isNext = !step.done && steps.slice(0, i).every(s => s.done);
              return (
                <div key={i} className="rounded-xl flex flex-col items-center gap-2 p-3 justify-center" style={{
                  backgroundColor: step.done ? 'rgba(16,185,129,0.1)' : isNext ? 'rgba(16,185,129,0.05)' : 'rgba(180,200,220,0.04)',
                  border: `1px solid ${step.done ? 'rgba(16,185,129,0.2)' : isNext ? 'rgba(16,185,129,0.12)' : BORDER}`,
                }}>
                  <div className="w-8 h-8 rounded-full flex items-center justify-center" style={{
                    backgroundColor: step.done ? ACCENT : isNext ? 'rgba(16,185,129,0.15)' : 'rgba(180,200,220,0.07)',
                    color: step.done ? NAVY : isNext ? ACCENT : STEEL,
                  }}>
                    {step.done ? <CheckCircle2 size={14} /> : <Icon size={14} />}
                  </div>
                  <span className="text-[10px] font-bold text-center leading-tight" style={{ color: step.done ? ACCENT : isNext ? WHITE : STEEL }}>
                    {step.shortLabel}
                  </span>
                </div>
              );
            })}
          </div>

          {nextStep && (
            <a href="#" className="mt-3 inline-flex self-start items-center gap-1.5 px-4 py-2 rounded-xl font-bold text-xs"
              style={{ backgroundColor: ACCENT, color: NAVY, textDecoration: 'none' }}>
              <Rocket size={11} />
              Continuar: {nextStep.label} →
            </a>
          )}
        </div>

        {/* Tile B — Bot KPI tower: narrow, full height */}
        <div className="col-span-1 rounded-2xl p-4 flex flex-col gap-3" style={{ backgroundColor: CARD2, border: `1px solid ${BORDER}` }}>
          <p className="text-[10px] font-bold uppercase tracking-widest" style={{ color: STEEL }}>Estado IA</p>

          {/* 4 mini KPIs stacked */}
          {[
            { label:'Bot',        value:'Inactivo', color:'#F87171', tagBg:'rgba(248,113,113,0.1)' },
            { label:'Convs.',     value:'0',        color:SILVER,    tagBg:'rgba(180,200,220,0.06)' },
            { label:'KB',         value:'0 ent.',   color:'#FDE047', tagBg:'rgba(253,224,71,0.08)' },
            { label:'Handoffs',   value:'0',        color:ACCENT,    tagBg:'rgba(16,185,129,0.08)' },
          ].map((k, i) => (
            <div key={i} className="flex-1 flex flex-col justify-center rounded-xl px-3 py-2.5" style={{ backgroundColor: k.tagBg, border: `1px solid ${BORDER}` }}>
              <p className="text-[10px] font-bold uppercase tracking-wider mb-1" style={{ color: STEEL }}>{k.label}</p>
              <p className="text-lg font-extrabold leading-none" style={{ color: k.color }}>{k.value}</p>
            </div>
          ))}
        </div>
      </div>

      {/* ══ ROW 2: Chart (2/5) + Funnel (2/5) + Channels (1/5) ══ */}
      <div className="grid grid-cols-5 gap-3">

        {/* Tile C — Chart */}
        <div className="col-span-2 rounded-2xl p-4" style={{ backgroundColor: CARD, border: `1px solid ${BORDER}` }}>
          <div className="flex items-center justify-between mb-3">
            <p className="text-xs font-bold" style={{ color: SILVER }}>Volumen semanal</p>
            <span className="text-[10px] font-semibold" style={{ color: ACCENT }}>msg/día</span>
          </div>
          <div className="h-24 flex items-end gap-1.5 px-1">
            {chartData.map((d, i) => {
              const isMax = d.v === 95;
              return (
                <div key={d.d} className="flex-1 flex flex-col items-center gap-1">
                  <div className="w-full rounded-t-md" style={{
                    height: `${(d.v / 95) * 100}%`,
                    background: isMax ? `linear-gradient(to top, ${ACCENT_DARK}, ${ACCENT})` : 'rgba(96,165,250,0.2)',
                  }} />
                  <span className="text-[9px]" style={{ color: isMax ? ACCENT : STEEL }}>{d.d}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Tile D — Funnel */}
        <div className="col-span-2 rounded-2xl p-4" style={{ backgroundColor: CARD, border: `1px solid ${BORDER}` }}>
          <p className="text-xs font-bold mb-3" style={{ color: SILVER }}>Embudo RAG</p>
          <div className="space-y-2.5">
            {[
              { label:'Recibidos',    val:'8.412', pct:100, color:'#60A5FA' },
              { label:'Intenciones',  val:'7.318', pct:87,  color:'#C084FC' },
              { label:'Resueltos KB', val:'6.561', pct:78,  color:'#4ADE80' },
              { label:'Fallback IA',  val:'757',   pct:9,   color:'#FDE047' },
              { label:'Escalados',    val:'589',   pct:7,   color:'#FCA5A5' },
            ].map(f => (
              <div key={f.label}>
                <div className="flex justify-between mb-0.5">
                  <span className="text-[10px]" style={{ color: STEEL }}>{f.label}</span>
                  <span className="text-[10px] font-bold" style={{ color: SILVER }}>{f.val}</span>
                </div>
                <div className="h-1.5 rounded-full" style={{ backgroundColor: 'rgba(180,200,220,0.07)' }}>
                  <div className="h-full rounded-full" style={{ width: `${f.pct}%`, backgroundColor: f.color }} />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Tile E — Channels tower */}
        <div className="col-span-1 rounded-2xl p-3 flex flex-col gap-2" style={{ backgroundColor: CARD2, border: `1px solid ${BORDER}` }}>
          <p className="text-[10px] font-bold uppercase tracking-widest mb-1" style={{ color: STEEL }}>Canales</p>
          {[
            { icon:MessageCircle, ic:'#F87171', title:'WhatsApp', status:'Inactivo',   sc:'#F87171', sb:'rgba(248,113,113,0.1)' },
            { icon:LayoutGrid,    ic:'#60A5FA', title:'Catálogo', status:'Inactivo',   sc:'#FDE047', sb:'rgba(253,224,71,0.08)' },
            { icon:Mail,          ic:'#60A5FA', title:'Gmail',    status:'Escaneando', sc:'#93C5FD', sb:'rgba(147,197,253,0.08)' },
            { icon:Database,      ic:'#FDE047', title:'Postgres', status:'OK',         sc:'#4ADE80', sb:'rgba(74,222,128,0.08)' },
          ].map((ch, i) => (
            <div key={i} className="flex-1 flex items-center gap-2 px-2.5 py-2 rounded-xl" style={{ backgroundColor: CARD3, border: `1px solid ${BORDER}` }}>
              <div className="w-6 h-6 rounded-lg flex items-center justify-center flex-shrink-0" style={{ backgroundColor: `${ch.ic}18` }}>
                <ch.icon size={12} style={{ color: ch.ic }} />
              </div>
              <span className="text-[10px] font-semibold flex-1 truncate" style={{ color: SILVER }}>{ch.title}</span>
              <span className="text-[9px] font-bold flex-shrink-0" style={{ color: ch.sc }}>{ch.status}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ══ ROW 3: Module Grid — 4-col equal weight ══ */}
      <div className="grid grid-cols-4 gap-2.5">
        {modules.map((m, i) => (
          <a key={i} href="#" className="rounded-xl p-3.5 flex flex-col gap-2.5 group hover:border-green-500/20 transition-all"
            style={{ backgroundColor: CARD, border: `1px solid ${BORDER}`, textDecoration: 'none' }}>
            {/* Module header */}
            <div className="flex items-center gap-2">
              <div className="w-7 h-7 rounded-lg flex items-center justify-center flex-shrink-0" style={{ backgroundColor: m.ib }}>
                <m.icon size={13} style={{ color: m.ic }} />
              </div>
              <span className="text-[11px] font-bold flex-1 leading-tight" style={{ color: SILVER }}>{m.title}</span>
              <ChevronRight size={11} className="opacity-20 group-hover:opacity-60 transition-opacity" style={{ color: SILVER }} />
            </div>
            {/* Key value — focal number */}
            <div className="px-0.5">
              <p className="text-lg font-extrabold leading-none" style={{ color: m.ic }}>{m.kv}</p>
              <p className="text-[10px] mt-0.5" style={{ color: STEEL }}>{m.ks}</p>
            </div>
            {/* Secondary metrics */}
            <div className="space-y-1.5 pt-1.5 border-t" style={{ borderColor: BORDER }}>
              {m.rows.map((r: any) => (
                <div key={r.l} className="flex items-center justify-between">
                  <span className="text-[10px]" style={{ color: STEEL }}>{r.l}</span>
                  <span className="text-[11px] font-bold" style={{ color: r.a ? ACCENT : r.w ? '#FCA5A5' : SILVER }}>{r.v}</span>
                </div>
              ))}
            </div>
          </a>
        ))}
      </div>

    </div>
  );
}

