{/* 4 KPI cards — mezcla de datos reales e indicadores de demo */}
<div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">

  {/* Card 1: Estado real del bot */}
  <div className="bg-navy-card border border-silver/15 rounded-2xl p-5">
    <div className="text-[10px] font-bold text-cool-steel/70 uppercase tracking-wider mb-2">Estado del bot</div>
    {isAuthed ? (
      <>
        <div className="flex items-center gap-2 mb-1">
          <span className={`w-2 h-2 rounded-full flex-shrink-0 ${status.active ? "bg-cl-accent animate-pulse" : "bg-red-400"}`} />
          <span className={`text-2xl font-extrabold ${status.active ? "text-cl-accent" : "text-red-400"}`}>
            {status.active ? "Activo" : "Inactivo"}
          </span>
        </div>
        <div className={`text-xs mt-1 flex items-center gap-1 ${status.configured ? "text-cl-accent" : "text-red-400"}`}>
          <i className={`ti ${status.configured ? "ti-circle-check" : "ti-alert-circle"}`} />
          {status.configured ? "WhatsApp conectado" : "Sin WhatsApp"}
        </div>
      </>
    ) : (
      <div className="text-2xl font-extrabold text-cool-steel/40">—</div>
    )}
  </div>

  {/* Card 2: Conversaciones reales */}
  <div className="bg-navy-card border border-silver/15 rounded-2xl p-5">
    <div className="text-[10px] font-bold text-cool-steel/70 uppercase tracking-wider mb-2">Conversaciones</div>
    {isAuthed ? (
      <>
        <div className="text-3xl font-extrabold text-white">
          {status.conversationCount.toLocaleString("es-AR")}
        </div>
        <div className="text-xs mt-2 flex items-center gap-1 text-cool-steel">
          <i className="ti ti-messages" /> total acumulado
        </div>
      </>
    ) : (
      <div className="text-3xl font-extrabold text-cool-steel/40">—</div>
    )}
  </div>

  {/* Card 3: Knowledge base real */}
  <div className="bg-navy-card border border-silver/15 rounded-2xl p-5">
    <div className="text-[10px] font-bold text-cool-steel/70 uppercase tracking-wider mb-2">Base de conocimiento</div>
    {isAuthed ? (
      <>
        <div className="text-3xl font-extrabold text-white">
          {status.knowledgeCount}
        </div>
        <div className={`text-xs mt-2 flex items-center gap-1 ${status.knowledgeCount > 0 ? "text-cl-accent" : "text-red-400"}`}>
          <i className={`ti ${status.knowledgeCount > 0 ? "ti-book" : "ti-alert-circle"}`} />
          {status.knowledgeCount > 0 ? "entradas indexadas" : "KB vacía — agregá contenido"}
        </div>
      </>
    ) : (
      <div className="text-3xl font-extrabold text-cool-steel/40">—</div>
    )}
  </div>

  {/* Card 4: Handoffs pendientes */}
  <div className="bg-navy-card border border-silver/15 rounded-2xl p-5">
    <div className="text-[10px] font-bold text-cool-steel/70 uppercase tracking-wider mb-2">Handoffs activos</div>
    {isAuthed ? (
      <>
        <div className="text-3xl font-extrabold text-white">
          {convs.filter((c) => c.handoffMode).length}
        </div>
        <div className={`text-xs mt-2 flex items-center gap-1 ${convs.some((c) => c.handoffMode) ? "text-orange-400" : "text-cool-steel"}`}>
          <i className={`ti ${convs.some((c) => c.handoffMode) ? "ti-alert-triangle" : "ti-robot"}`} />
          {convs.some((c) => c.handoffMode) ? "requieren respuesta manual" : "bot respondiendo todo"}
        </div>
      </>
    ) : (
      <div className="text-3xl font-extrabold text-cool-steel/40">—</div>
    )}
  </div>
</div>
